          <button onClick={() => scrollToSection('blog')} className="hover:text-lime-600 transition-colors">Writings</button>
          <button 
            onClick={() => scrollToSection('contact')} 
            className="px-4 py-2 bg-black text-white rounded hover:bg-lime-600 hover:text-black transition-all duration-300 font-mono text-xs"
          >
            Let's Talk
